namespace pocketmine\network\mcpe\protocol { class ClientboundPacket {} class DataPacket extends ClientboundPacket {} final class AvailableCommandsPacket extends DataPacket { public const NETWORK_ID=76; public const ARG_FLAG_ENUM=0x200000; public const ARG_TYPE_VALUE=0; public const ARG_TYPE_INT=1; public const ARG_TYPE_FLOAT=2; public const ARG_TYPE_STRING=3; public const ARG_TYPE_TARGET=4; public const ARG_TYPE_POSITION=5; public array $commandData = []; } final class UpdateSoftEnumPacket extends ClientboundPacket { public const TYPE_ADD=0; public const TYPE_REMOVE=1; public const TYPE_SET=2; public string $enumName=''; public array $values=[]; public int $type=self::TYPE_SET; } }
namespace pocketmine\network\mcpe\protocol\serializer { final class AvailableCommandsPacketDisassembler { public static function disassemble(\pocketmine\network\mcpe\protocol\AvailableCommandsPacket $packet): array { return []; } } final class AvailableCommandsPacketAssembler { public static function assemble(array $commandData, array $dynamicEnums = [], array $softEnums = []): \pocketmine\network\mcpe\protocol\AvailableCommandsPacket { return new \pocketmine\network\mcpe\protocol\AvailableCommandsPacket(); } } }
namespace pocketmine\network\mcpe\protocol\types\command { final class CommandHardEnum { public function __construct(private string $name, private array $values = []) {} public function getName(): string { return $this->name; } public function getValues(): array { return $this->values; } } final class CommandSoftEnum { public function __construct(private string $name, private array $values = []) {} public function getName(): string { return $this->name; } public function getValues(): array { return $this->values; } } final class CommandParameter { public ?CommandHardEnum $enum = null; public string $paramName=''; public int $paramType=0; public bool $isOptional=false; public static function standard(string $name, int $type, int $flags = 0, bool $optional = false): self { $p = new self(); $p->paramName=$name; $p->paramType=$type; $p->isOptional=$optional; return $p; } public static function enum(string $name, CommandHardEnum $enum, int $flags = 0, bool $optional = false): self { $p = self::standard($name, 0, $flags, $optional); $p->enum = $enum; return $p; } public static function softEnum(string $name, CommandSoftEnum $enum, int $flags = 0, bool $optional = false): self { return self::standard($name, 0, $flags, $optional); } } final class CommandOverload { public function __construct(public bool $chaining = false, public array $parameters = []) {} } }

